-- BATCH 4: BUSINESS (5 templates)

INSERT INTO dream_templates (slug, title, category, description, emoji, color, big_wins, small_wins, daily_activities, onboarding_questions, alternative_futures) VALUES
('entrepreneur','Entrepreneur Profesional','Business','Jadilah entrepreneur visioner yang membangun bisnis dari nol. Setiap tantangan adalah peluang untuk berinovasi dan menciptakan dampak nyata.','🚀','#8B5CF6','["Ide bisnis pertama yang validasi","Buat produk minimum viable (MVP)","Dapat customer pertama","Break even point tercapai","Mendapatkan revenue 10 juta","Mendapatkan investor pertama","Bisnis mencapai profit 100 juta"]'::jsonb,'["Riset pasar 30 menit","Kerjakan product development","Follow up leads","Review keuangan bisnis","Buat konten marketing","Networking dengan pebisnis","Refleksi + evaluasi bisnis"]'::jsonb,'[{"dimension": "Strategi", "items": ["Review business plan", "Analisis kompetitor", "Riset market trends"]},{"dimension": "Product", "items": ["Product development", "User testing", "Iterasi berdasarkan feedback"]},{"dimension": "Marketing", "items": ["Konten sosial media", "Email marketing", "Iklan digital"]},{"dimension": "Sales", "items": ["Cold outreach", "Follow up leads", "Closing deals"]},{"dimension": "Finance", "items": ["Cek cash flow", "Review pengeluaran", "Proyeksi revenue"]},{"dimension": "Growth", "items": ["Baca buku bisnis", "Networking event", "Cari mentor"]}]'::jsonb,'[{"question": "Tahap bisnis kamu saat ini?", "type": "single_select", "options": [{"label": "Ide", "value": "ide"}, {"label": "Validasi", "value": "validasi"}, {"label": "Launch", "value": "launch"}, {"label": "Scale", "value": "scale"}]},{"question": "Bidang bisnis favorit?", "type": "single_select", "options": [{"label": "Teknologi", "value": "teknologi"}, {"label": "F&B", "value": "f&b"}, {"label": "Fashion", "value": "fashion"}, {"label": "Jasa", "value": "jasa"}]},{"question": "Target utama bisnis?", "type": "single_select", "options": [{"label": "Profit konsisten", "value": "profit"}, {"label": "Skala nasional", "value": "nasional"}, {"label": "Funding", "value": "funding"}, {"label": "Exit strategy", "value": "exit"}]},{"question": "Skill paling penting untuk entrepreneur?", "type": "single_select", "options": [{"label": "Leadership", "value": "leadership"}, {"label": "Sales", "value": "sales"}, {"label": "Financial", "value": "financial"}, {"label": "Problem solving", "value": "problem-solving"}]}]'::jsonb,'[{"title": "Angel Investor", "description": "Berinvestasi di startup early-stage dan membantu mereka bertumbuh.", "slug": "alternative-angel-investor"},{"title": "Business Coach", "description": "Membimbing entrepreneur lain mencapai kesuksesan bisnis.", "slug": "alternative-business-coach"},{"title": "Venture Capitalist", "description": "Mengelola dana investasi untuk startup potensial.", "slug": "alternative-vc"}]'::jsonb),
('digital-marketer','Digital Marketer Profesional','Business','Jadilah digital marketer yang menguasai seni promosi di era digital. Dari SEO hingga iklan berbayar, setiap strategi adalah jalan menuju pertumbuhan.','📈','#3B82F6','["Menyelesaikan kursus marketing digital","Mengelola campaign iklan pertama","Mencapai ROAS 3x","Mengelola budget 10 juta","Memenangkan award marketing","Memimpin tim marketing","Membuat strategi marketing 360"]'::jsonb,'["Cek analytics harian","Optimasi campaign iklan","Buat konten marketing","SEO audit website","A/B testing landing page","Report performance","Belajar tools marketing baru"]'::jsonb,'[{"dimension": "Analytics", "items": ["Cek Google Analytics", "Review campaign performance", "Analisis konversi"]},{"dimension": "Iklan", "items": ["Optimasi Google Ads", "Facebook Ads tuning", "A/B testing creatives"]},{"dimension": "SEO", "items": ["Keyword research", "On-page SEO audit", "Backlink strategy"]},{"dimension": "Konten", "items": ["Buat copywriting", "Desain visual ads", "Video marketing"]},{"dimension": "Email Marketing", "items": ["Segmentasi list", "Buat email sequence", "A/B testing subject"]},{"dimension": "Strategy", "items": ["Competitor analysis", "Buat marketing calendar", "Budget planning"]}]'::jsonb,'[{"question": "Bidang marketing favorit?", "type": "single_select", "options": [{"label": "SEO", "value": "seo"}, {"label": "Paid Ads", "value": "paid-ads"}, {"label": "Social Media", "value": "social-media"}, {"label": "Content Marketing", "value": "content-marketing"}]},{"question": "Level pengalaman marketing?", "type": "single_select", "options": [{"label": "Pemula", "value": "pemula"}, {"label": "Intermediate", "value": "intermediate"}, {"label": "Advance", "value": "advance"}, {"label": "Expert", "value": "expert"}]},{"question": "Target utama karir marketing?", "type": "single_select", "options": [{"label": "Marketing Manager", "value": "marketing-manager"}, {"label": "Growth Hacker", "value": "growth-hacker"}, {"label": "CMO", "value": "cmo"}, {"label": "Agency Owner", "value": "agency-owner"}]},{"question": "Metrik terpenting dalam marketing?", "type": "single_select", "options": [{"label": "ROAS/ROI", "value": "roas"}, {"label": "Conversion Rate", "value": "conversion-rate"}, {"label": "Traffic", "value": "traffic"}, {"label": "Customer LTV", "value": "ltv"}]}]'::jsonb,'[{"title": "Growth Marketing Manager", "description": "Mengelola strategi pertumbuhan untuk perusahaan digital.", "slug": "alternative-growth-marketing"},{"title": "SEO Specialist", "description": "Spesialis optimasi mesin pencari untuk website.", "slug": "alternative-seo-specialist"},{"title": "Marketing Agency Owner", "description": "Mendirikan agency marketing digital sendiri.", "slug": "alternative-marketing-agency"}]'::jsonb),
('social-media-manager','Social Media Manager Profesional','Business','Jadilah social media manager yang membangun brand presence di dunia digital. Konten kreatif, strategi engage, dan analisis data adalah kunci suksesmu.','📱','#EC4899','["Mengelola akun sosial media pertama","Mencapai 10.000 followers organik","Viral campaign pertama","Mengelola budget iklan sosmed","Kolaborasi dengan influencer","Brand partnership sukses","Memimpin tim sosial media"]'::jsonb,'["Cek mentions & komentar","Buat konten calendar","Produksi konten harian","Scheduling posts","Interaksi dengan followers","Analisis insight mingguan","Report performa"]'::jsonb,'[{"dimension": "Content Planning", "items": ["Buat konten calendar", "Brainstorm ide konten", "Riset trending topics"]},{"dimension": "Content Creation", "items": ["Buat visual posts", "Tulis copy caption", "Edit video reels"]},{"dimension": "Scheduling", "items": ["Jadwalkan posts", "Optimasi posting time", "Cross-platform posting"]},{"dimension": "Engagement", "items": ["Balas komentar + DM", "Interaksi komunitas", "Manage customer service"]},{"dimension": "Analytics", "items": ["Review insight harian", "Analisis demografi", "Report bulanan"]},{"dimension": "Strategy", "items": ["Competitor analysis", "Trend forecasting", "Campaign planning"]}]'::jsonb,'[{"question": "Platform sosmed favorit?", "type": "single_select", "options": [{"label": "Instagram", "value": "instagram"}, {"label": "TikTok", "value": "tiktok"}, {"label": "LinkedIn", "value": "linkedin"}, {"label": "Twitter/X", "value": "twitter"}]},{"question": "Level pengalaman sosmed?", "type": "single_select", "options": [{"label": "Pemula", "value": "pemula"}, {"label": "Hobi", "value": "hobi"}, {"label": "Semi-pro", "value": "semi-pro"}, {"label": "Profesional", "value": "profesional"}]},{"question": "Target utama karir sosmed?", "type": "single_select", "options": [{"label": "Brand manager", "value": "brand-manager"}, {"label": "Content strategist", "value": "content-strategist"}, {"label": "Agency owner", "value": "agency-owner"}, {"label": "Freelance", "value": "freelance"}]},{"question": "Metrik terpenting sosmed?", "type": "single_select", "options": [{"label": "Engagement rate", "value": "engagement-rate"}, {"label": "Followers growth", "value": "followers-growth"}, {"label": "Reach", "value": "reach"}, {"label": "Conversion", "value": "conversion"}]}]'::jsonb,'[{"title": "Brand Strategist", "description": "Mengembangkan strategi brand komprehensif untuk perusahaan.", "slug": "alternative-brand-strategist"},{"title": "Influencer Marketing Manager", "description": "Mengelola campaign influencer untuk brand.", "slug": "alternative-influencer-manager"},{"title": "Digital PR Specialist", "description": "Membangun reputasi digital brand melalui media dan influencer.", "slug": "alternative-digital-pr"}]'::jsonb),
('event-organizer','Event Organizer Profesional','Business','Jadilah event organizer yang menciptakan acara tak terlupakan. Dari konsep hingga eksekusi, setiap detail adalah kunci kesuksesan event.','🎪','#F43F5E','["Mengelola event kecil pertama","Event dengan 100+ peserta","Mengelola budget 50 juta","Kolaborasi dengan sponsor","Event skala nasional","Memenangkan award event","Event internasional sukses"]'::jsonb,'["Riset venue & vendor","Koordinasi timeline event","Follow up klien","Cek list kebutuhan","Promosi event","Briefing tim","Evaluasi post-event"]'::jsonb,'[{"dimension": "Perencanaan", "items": ["Buat konsep event", "Riset venue", "Buat timeline"]},{"dimension": "Koordinasi", "items": ["Hubungi vendor", "Negosiasi kontrak", "Briefing tim"]},{"dimension": "Operasional", "items": ["Cek list kebutuhan", "Koordinasi logistik", "Manajemen budget"]},{"dimension": "Marketing", "items": ["Buat promo event", "Manage registrasi", "Follow up peserta"]},{"dimension": "Eksekusi", "items": ["On-site coordination", "Manajemen acara", "Problem solving"]},{"dimension": "Evaluasi", "items": ["Survey kepuasan", "Report post-event", "Dokumentasi"]}]'::jsonb,'[{"question": "Jenis event favorit?", "type": "single_select", "options": [{"label": "Wedding", "value": "wedding"}, {"label": "Corporate", "value": "corporate"}, {"label": "Music concert", "value": "music"}, {"label": "Exhibition", "value": "exhibition"}]},{"question": "Level pengalaman EO?", "type": "single_select", "options": [{"label": "Pemula", "value": "pemula"}, {"label": "Pernah bantu event", "value": "pernah-bantu"}, {"label": "Semi-pro", "value": "semi-pro"}, {"label": "Profesional", "value": "profesional"}]},{"question": "Target utama karir EO?", "type": "single_select", "options": [{"label": "EO company", "value": "eo-company"}, {"label": "Wedding organizer", "value": "wedding"}, {"label": "Corporate event", "value": "corporate"}, {"label": "Music festival", "value": "music-festival"}]},{"question": "Aspek terpenting dalam event?", "type": "single_select", "options": [{"label": "Konsep", "value": "konsep"}, {"label": "Budget", "value": "budget"}, {"label": "Tim", "value": "tim"}, {"label": "Vendor", "value": "vendor"}]}]'::jsonb,'[{"title": "Wedding Planner", "description": "Mengkhususkan diri dalam merencanakan pernikahan impian.", "slug": "alternative-wedding-planner"},{"title": "Corporate Event Manager", "description": "Mengelola event korporat dan konferensi berskala besar.", "slug": "alternative-corporate-event"},{"title": "Venue Manager", "description": "Mengelola venue event dan operasional harian.", "slug": "alternative-venue-manager"}]'::jsonb),
('financial-planner','Financial Planner Profesional','Business','Jadilah financial planner yang membantu orang mencapai kebebasan finansial. Dari budgeting hingga investasi, setiap saran adalah langkah menuju masa depan yang aman.','💰','#10B981','["Membuat perencana keuangan pribadi","Membantu 10 klien pertama","Sertifikasi perencana keuangan","Mengelola portofolio 100 juta","Khitbah di seminar finansial","Buka kantor konsultan sendiri","Buku best seller finansial"]'::jsonb,'["Review portofolio klien","Riset instrumen investasi","Buat financial plan","Follow up klien","Update regulasi pajak","Buat konten edukasi","Networking dengan advisor"]'::jsonb,'[{"dimension": "Analisis", "items": ["Review laporan keuangan klien", "Analisis cash flow", "Evaluasi portofolio"]},{"dimension": "Perencanaan", "items": ["Buat financial plan", "Strategi investasi", "Perencanaan pajak"]},{"dimension": "Riset", "items": ["Riset instrumen investasi", "Update market news", "Analisis risiko"]},{"dimension": "Klien", "items": ["Konsultasi dengan klien", "Follow up progress", "Review tujuan finansial"]},{"dimension": "Edukasi", "items": ["Buat konten finansial", "Webinar edukasi", "Blog artikel"]},{"dimension": "Bisnis", "items": ["Networking dengan advisor", "Cari klien baru", "Manajemen jadwal"]}]'::jsonb,'[{"question": "Bidang finansial favorit?", "type": "single_select", "options": [{"label": "Investasi", "value": "investasi"}, {"label": "Asuransi", "value": "asuransi"}, {"label": "Pajak", "value": "pajak"}, {"label": "Retirement", "value": "retirement"}]},{"question": "Level pengalaman finansial?", "type": "single_select", "options": [{"label": "Pemula", "value": "pemula"}, {"label": "Menengah", "value": "menengah"}, {"label": "Mahir", "value": "mahir"}, {"label": "Bersertifikasi", "value": "bersertifikasi"}]},{"question": "Target utama karir finansial?", "type": "single_select", "options": [{"label": "Financial advisor", "value": "financial-advisor"}, {"label": "Wealth manager", "value": "wealth-manager"}, {"label": "Kantor sendiri", "value": "kantor-sendiri"}, {"label": "Pendidik finansial", "value": "pendidik-finansial"}]},{"question": "Produk investasi favorit?", "type": "single_select", "options": [{"label": "Saham", "value": "saham"}, {"label": "Reksadana", "value": "reksadana"}, {"label": "Emas", "value": "emas"}, {"label": "Properti", "value": "properti"}]}]'::jsonb,'[{"title": "Wealth Manager", "description": "Mengelola portofolio investasi untuk high-net-worth individuals.", "slug": "alternative-wealth-manager"},{"title": "Tax Consultant", "description": "Membantu klien mengoptimalkan perencanaan pajak.", "slug": "alternative-tax-consultant"},{"title": "Financial Educator", "description": "Mengedukasi masyarakat tentang literasi keuangan.", "slug": "alternative-financial-educator"}]'::jsonb)
